 1	import {
 2	  Alert,
 3	  Button,
 4	  ButtonVariant,
 5	  Modal,
 6	  ModalVariant,
 7	} from "@patternfly/react-core";
 8	import { deleteNodeHealthCheck } from "apis/nodeHealthCheckApis";
 9	import * as React from "react";
10	import { useNodeHealthCheckTranslation } from "localization/useNodeHealthCheckTranslation";
11	import { NodeHealthCheckModalProps } from "./propTypes";
12	
13	const DeleteModal: React.FC<
14	  NodeHealthCheckModalProps & { onDelete: () => void }
15	> = ({ isOpen, nodeHealthCheck, onClose, onDelete }) => {
16	  const [error, setError] = React.useState<boolean>();
17	  const [isDeleting, setIsDeleting] = React.useState<boolean>(false);
18	  const { t } = useNodeHealthCheckTranslation();
19	  if (!isOpen) {
20	    return null;
21	  }
22	  const onClickDelete = async () => {
23	    try {
24	      setIsDeleting(true);
25	      await deleteNodeHealthCheck(nodeHealthCheck);
26	      setIsDeleting(false);
27	      onClose();
28	      if (onDelete) {
29	        onDelete();
30	      }
31	    } catch (err) {
32	      setIsDeleting(false);
33	      setError(err);
34	    }
35	  };
36	  const name = nodeHealthCheck.metadata?.name;
37	  return (
38	    <Modal
39	      className="nhc-modal"
40	      title={t("Delete NodeHealthCheck")}
41	      titleIconVariant="warning"
42	      isOpen={isOpen}
43	      onClose={onClose}
44	      variant={ModalVariant.small}
45	      actions={[
46	        <Button
47	          aria-label="delete"
48	          key="confirm"
49	          variant={ButtonVariant.danger}
50	          onClick={() => void onClickDelete()}
51	          isLoading={isDeleting}
52	          data-test="confirm"
53	          isDisabled={isDeleting}
54	        >
55	          {t("Delete")}
56	        </Button>,
57	        <Button
58	          key="cancel"
59	          variant={ButtonVariant.secondary}
60	          onClick={onClose}
61	          aria-label="cancel"
62	          isDisabled={isDeleting}
63	        >
64	          {t("Cancel")}
65	        </Button>,
66	      ]}
67	    >
68	      {t("Are you sure you want to delete {{name}}?", { name })}
69	      {error && (
70	        <Alert
71	          variant="danger"
72	          title={t("Failed to delete {{name}}", { name })}
73	          isInline
74	        />
75	      )}
76	    </Modal>
77	  );
78	};
79	
80	export default DeleteModal;

